INSERT INTO public.photos VALUES (25851, 'Calle de Pignatelli c.1995', 'Imagen capturada en el tramo de los impares de la calle de Ram├│n Pignatelli comprendido entre el despartidero con la calle de Jos├® Zamoray, y la calle de la Escopeter├¡a. Casi centra la imagen el Bar-Restaurante-Mes├│n El Pajarcico, sito en el n┬║ 61 de esta calle. Abierto en 1973 por Eduardo Burgar Asensio, era uno de los lugares de referencia en las inmediaciones al Coso de la Misericordia de la aut├®ntica "comida casera" aut├│ctona (con perlas culinarias tales que huevos fritos con longaniza, jud├¡as con jarrete, sopa de cocido, morcilla de sangre y arroz), adem├ís de contar con una galer├¡a de decenas de estupendos jamones. Autor desde 1982 de varios libros, como se├▒ala el anuncio junto a la entrada, "Cada 4 men├║s regalo un libro de mi colecci├│n". Este antropol├│gico establecimiento de restauraci├│n fue cerrado a comienzos de 2013.', 1995, 1995, 1995, 'Anos 90', 'CASCO HIST├ôRICO', 41.65402800, -0.88789700, '0101000020E6100000ABED26F8A669ECBF8A558330B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48085149282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48085149282.webp', 'https://www.flickr.com/photos/zaragozaantigua/48085149282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20908, 'Plano del Arrabal 1776', 'Plano del proyecto de ordenaci├│n de las calles del Arrabal de Zaragoza en 1776, con indicaci├│n de los hitos del entorno, por Thomas Sanz. Arriba a la izquierda, el Puente de Piedra, seguido del nuevo trazado de su uni├│n con la actual avenida de Catalu├▒a. Aparecen tambi├®n los conventos de Altab├ís, de San L├ízaro y de Jes├║s, adem├ís del Puente de Tablas. Fuente: eszaragoza.blogspot.com.es/2014/09/rabal-de-zaragoza-plan...', 1776, 1776, 1776, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65800000, -0.87185000, '0101000020E61000002E90A0F831E6EBBF4E62105839D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15296644736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15296644736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15296644736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20952, 'Convento de Jes├║s 1855', 'Convento de Jes├║s de Zaragoza. Valent├¡n Carderera. L├ípiz negro y aguadas sobre papel blanco, 1855. El convento de Nuestra Se├▒ora de Jes├║s de Zaragoza, fundado en 1447 por los franciscanos, estuvo situado en el Arrabal, dentro del barrio actual del mismo nombre. En 1836 se desacraliz├│. En el momento del dibujo, la torre ya hab├¡a perdido el chapitel. Fuente: "Viaje art├¡stico por Arag├│n de Valent├¡n Carderera", Jos├® Mar├¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci├│n L├ízaro Galdiano, 2013.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65732100, -0.87073400, '0101000020E61000000B7DB08C0DDDEBBFADFC321823D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15104343602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15104343602.webp', 'https://www.flickr.com/photos/zaragozaantigua/15104343602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20990, 'Zaragoza 1808', 'En el dibujo, abajo, a la izquierda, figura "Vista de Zaragoza en 1808", aunque el t├¡tulo oficial de este esbozo es "El puente de piedra sobre el Ebro en Zaragoza". Fue obra de Juan G├ílvez como preparatorio para la serie "Las ruinas de Zaragoza", sobre los desastres de la guerra de 1808-1809. A la izquierda, la fachada de la ciudad en la margen derecha del r├¡o Ebro, desde la Portaza, hasta el Pilar. El puente de Piedra centra la imagen. A la derecha, el Arrabal, con el convento de San L├ízaro, y unos aguadores, en primer plano, cargando mercanc├¡a del Ebro. Fuente visual: ceres.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65661600, -0.87329600, '0101000020E6100000A148F7730AF2EBBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24868250432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24868250432.webp', 'https://www.flickr.com/photos/zaragozaantigua/24868250432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21005, 'El Pilar c.1860', 'Colecci├│n Madrazo, Madrid; familia Daza Campos, Madrid (Adquirido en 2006 por el Museo del Prado). Autor an├│nimo. Antes de 1880. "Vista posterior de la Bas├¡lica del Pilar de Zaragoza." Imagen capturada desde la ribera izquierda, a la altura del cauce del r├¡o, incluyendo al Puente de Piedra en el cuadro.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65729800, -0.87327300, '0101000020E6100000965AEF37DAF1EBBFF4DC425722D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725216488.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725216488.webp', 'https://www.flickr.com/photos/zaragozaantigua/14725216488/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21248, 'Convento de San L├ízaro 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 34, Zaragoza 1908 - Centenario de los Sitios", 1907. "Magn├¡fico edificio emplazado al otro lado del Ebro. El r├¡o ba├▒a sus cimientos. Fue construido en 1224 por Don Jaime el Conquistador. Su proximidad al puente de Piedra, le hac├¡a ser apetecido por los franceses, a fin de cortar la comunicaci├│n entre Zaragoza y el Arrabal. Palafox lo utiliz├│ para instalar su cuartel, que fue ocupado el 8 de febrero por los franceses. El 18 del mismo mes, el general, enfermo, fue conducido desde all├¡ a una casa de la calle de Predicadores." Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20151214303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20151214303.webp', 'https://www.flickr.com/photos/zaragozaantigua/20151214303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21283, 'Puente de Piedra c.1900', 'Imagen para postal de la Fototipia Hauser y Menet, de Madrid, que captura una vista est├índar de Zaragoza titulada "El puente de Piedra y el Pilar". Fuente visual: www.delcampe.es/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65661600, -0.87329600, '0101000020E6100000A148F7730AF2EBBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24815087470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24815087470.webp', 'https://www.flickr.com/photos/zaragozaantigua/24815087470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21378, 'Cuartel de San L├ízaro c.1910', 'En la imagen, detalle de una fotograf├¡a del Archivo Coyne centrada en el Cuartel de San L├ízaro (cuerpo de guardia, o edificio longitudinal flanqueado por dos torreones, patio, y estructura defensiva triangular). A la derecha, refectorio superviviente, aunque muy deteriorado, del antiguo Convento del mismo nombre. Al fondo, la Estaci├│n del Norte. Fuente: Pilar Lop Ot├¡n, "Los conventos mercedarios de San L├ízaro y San Pedro Nolasco de Zaragoza", IFC, 2011', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15743356637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15743356637.webp', 'https://www.flickr.com/photos/zaragozaantigua/15743356637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21381, 'Vacas en el Ebro c.1910', 'Foto colecci├│n Francisco Pal├í, entre 1907 y 1912. Vacas abrevando en el r├¡o Ebro, con el Puente de Piedra y el Pilar al fondo. Fuente: www.facebook.com/photo.php?fbid=813589111997049&set=g...', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST├ôRICO', 41.65739200, -0.87322100, '0101000020E6100000F8C5A52A6DF1EBBF7653CA6B25D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15861592015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15861592015.webp', 'https://www.flickr.com/photos/zaragozaantigua/15861592015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21422, 'Estaci├│n del Norte c.1918', 'Imagen del mar de v├¡as de la estaci├│n del Norte junto a los antiguos almacenes y el sif├│n que salvaba el cauce de la acequia del Rabal, cerca de la curva que conduc├¡a al talud de la plaza de Altab├ís y al t├║nel de San L├ízaro. La fotograf├¡a se habr├¡a capturado junto a los muelles y and├®n principal de la estaci├│n. Al fondo, ├írboles de la carretera de Catalu├▒a y cuartel de San L├ízaro, y a la derecha, emerge la atalaya de la Seo, al otro lado del Ebro. A la izquierda, una composici├│n de dos veteranas locomotoras a vapor, posiblemente de la serie 100 (caldera vieja), fabricadas en 1860-61, y desguazadas unos a├▒os despu├®s. Fuente visual: Josep Maria Reitg Mart├¡, Ajuntament de Girona.', 1918, 1918, 1918, 'Anos 10', 'CASCO HIST├ôRICO', 41.65861500, -0.87316500, '0101000020E6100000FE60E0B9F7F0EBBFD8D30E7F4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31695262631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31695262631.webp', 'https://www.flickr.com/photos/zaragozaantigua/31695262631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21593, 'R├¡o Ebro c.1920', 'Vista de la margen izquierda del r├¡o Ebro, con el puente de Hierro al fondo. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST├ôRICO', 41.65700700, -0.87219100, '0101000020E610000079B29B19FDE8EBBF1D1F2DCE18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24870280546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24870280546.webp', 'https://www.flickr.com/photos/zaragozaantigua/24870280546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21631, 'Regulares 1922', 'Un grupo de soldados Regulares posa ante el puente de Piedra y el Pilar, desde la orilla del r├¡o Ebro en su margen izquierda, junto al cuartel de San L├ízaro. Fuente visual: www.todocoleccion.net', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST├ôRICO', 41.65750300, -0.87353100, '0101000020E61000008159A148F7F3EBBFCD02ED0E29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38863954005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38863954005.webp', 'https://www.flickr.com/photos/zaragozaantigua/38863954005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21702, 'Lavaderos del Puente del Pilar c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar y centrada en la pila de lavar ropa con una zona, en primer t├®rmino, para el aclarado de la ropa, y una segunda, posterior, para el lavado con jab├│n de tajo, que es donde realizan su trabajo ahora las lavanderas usuarias. A la izquierda y tras la alameda, la extensa zona de los tendederos. A la derecha, el lavadero a cubierto. Al fondo y en la margen derecha emergen la torre de santa Mar├¡a Magdalena, y la torre de San Carlos Borromeo y el seminario sacerdotal.', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST├ôRICO', 41.65752000, -0.87039500, '0101000020E6100000EE42739D46DAEBBFA33B889D29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15678319991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15678319991.webp', 'https://www.flickr.com/photos/zaragozaantigua/15678319991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22228, 'Arrabal c.1951', 'Desde un tren pr├│ximo a llegar a la estaci├│n del Norte, una pixelada imagen realizada a la altura de las traseras del convento de Santa Isabel de las Franciscanas de la Orden Tercera, a la derecha, con ingreso desde el n┬║ 2 de la calle del Sobrarbe. La vegataci├│n impide ver las traseras del Grupo Escolar C├índido Domingo. Al fondo, el templo del Pilar.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST├ôRICO', 41.65858900, -0.87345600, '0101000020E6100000D8D64FFF59F3EBBFAF40F4A44CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49773027303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49773027303.webp', 'https://www.flickr.com/photos/zaragozaantigua/49773027303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22508, 'Av. del Puente del Pilar 1962', 'Imagen capturada durante la construcci├│n de los grandes bloques de viviendas de renta limitada proyectados por J. M. Anasagasti y F. Barandiar├ín para la inmobiliaria Darsa en la manzana delimitada entre la avenida del Puente del Pilar, desde donde se ha tomado la foto, el camino del Puente de Tablas, a la izquierda, y la calle de Jes├║s, al fondo. Esta promoci├│n se realiz├│ donde estuvieron los lavaderos del Puente del Pilar.', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65709000, -0.87078400, '0101000020E61000007C293C6876DDEBBFAA436E861BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50874261132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50874261132.webp', 'https://www.flickr.com/photos/zaragozaantigua/50874261132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22554, 'Barrio de Jes├║s c.1978', 'Vista a├®rea del barrio de Jes├║s, en su parte m├ís inmediata al puente de Hierro y la ribera del Ebro. En primer t├®rmino, la antigua f├íbrica de colchones Pikolin, que ya en 1973 se hab├¡a trasladado a su nueva factor├¡a de la carretera de Logro├▒o. Al otro lado de la avenida del Puente del Pilar, los bloques de viviendas en la esquina con la calle de Cecilio Navarro, levantados en 1960 para empleados de la Compa├▒├¡a Telef├│nica Nacional de Espa├▒a. Al fondo y a la izquierda, una de las dos chimeneas de la Azucarera del Arrabal, en un entorno fabril y ferroviario que se extiende hasta el pol├¡gono industrial de Cogullada. Hacia el fondo y a la derecha se despliega el barrio de la Jota, vertebrado entre la avenida de Catalu├▒a, la calle del Molino de las Armas y la avenida de la Jota. Todav├¡a perviven campos de cultivo, que ir├ín siendo urbanizados en a├▒os posteriores.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST├ôRICO', 41.65680100, -0.86994700, '0101000020E6100000221B48179BD6EBBF747D1F0E12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15046959485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15046959485.webp', 'https://www.flickr.com/photos/zaragozaantigua/15046959485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22665, 'Puente de Hierro 1970', 'Imagen del entorno del puente de Hierro en la margen izquierda m├ís inmediata a la ribera del Ebro. Al fondo, construcci├│n de los bloques habitacionales entre las calles Cecilio Navarro, Puente de Tablas, calle de Jes├║s, y avenida del puente del Pilar. Fuente visual: Archivo P├║blico Municipal.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65667500, -0.86964600, '0101000020E6100000651C23D923D4EBBFE78C28ED0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22818134690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22818134690.webp', 'https://www.flickr.com/photos/zaragozaantigua/22818134690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22686, 'Estaci├│n del Norte 1970', 'Imagen en colores del mar de v├¡as que desde la Estaci├│n del Norte, o Arrabal, conduc├¡a por la ribera, pasando el t├║nel de San L├ízaro, hacia Ranillas, el antiguo puente del ferrocarril, y hasta la estaci├│n de Delicias, al otro lado del r├¡o Ebro. A la izquierda, asoma el cuartel de San L├ízaro, en el arranque de la avenida de Catalu├▒a. A la derecha, parte de las traseras del convento franciscano de Santa Isabel. Por encima sobresale el gigante desarrollista de 10 alturas ubicado entre las calles de Sixto Celorrio y Sobrarbe. Al fondo, la pareja de torres m├ís oriental de la iglesia metropolitana de El Pilar. Unos pocos a├▒os despu├®s, este enlace ferroviario, y la propia Estaci├│n del Norte, en claro decaimiento tras la apertura del nuevo enlace por Miraflores, ser├ín cerradas, primero al tr├ífico de pasajeros, y luego tambi├®n al de mercanc├¡as. El desmantelamiento del tendido fue r├ípido, al ritmo de los vertiginosos setenta del siglo pasado. Fuente visual: Arxiu Jordi Bibi├á www.flickr.com/photos/jbibia/10120046814/in/album-7215762...', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST├ôRICO', 41.65861500, -0.87316500, '0101000020E6100000FE60E0B9F7F0EBBFD8D30E7F4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26750481264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26750481264.webp', 'https://www.flickr.com/photos/zaragozaantigua/26750481264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23000, 'El Ebro a├▒os 90', 'Vista del r├¡o Ebro y su margen derecha, desde el puente de Hierro o del Pilar. Al fondo, torres de la Seo y del Pilar. Fuente: Foto para postal de Comercial Josan. Cesi├│n de la familia de Jos├® Mar├¡a Sanz Gonz├ílez a Rafael Castillejo. Dataci├│n y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HIST├ôRICO', 41.65665500, -0.87060400, '0101000020E61000007F8978EBFCDBEBBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26811061864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26811061864.webp', 'https://www.flickr.com/photos/zaragozaantigua/26811061864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23141, 'Aparcamiento de autobuses 2004', 'Foto: Mar├¡a Torres-Solanot. Aspecto del aparcamiento de autobuses sito entre el puente de Piedra (derecha, fuera de plano) y las traseras de la calle de Juliana Larena, en el solar del cuartel de San L├ízaro del barrio Jes├║s. Al fondo a la derecha, edificios de la esquina del Coso con el paseo de Echegaray y Caballero. Fuente: Heraldo de Arag├│n.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65805700, -0.87388700, '0101000020E610000021C9ACDEE1F6EBBFB2F336363BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31836528253.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31836528253.webp', 'https://www.flickr.com/photos/zaragozaantigua/31836528253/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23177, 'Calle de Funes 2008', 'Imagen de la arrabalera calle de Nicol├ís Funes capturada cuando a├║n perduraban, a la derecha, las parcelas de los antiguos n├║meros 6, 8, 10 y 12 de este vial, por cuyas traseras flu├¡a al aire, en tiempos, la hom├│nima acequia. Hacia la izquierda se abre la traves├¡a de Funes, y al fondo la calle se curvea para conducir al antiguo camino de las Tablas. M├ís al fondo, el molino de San L├ízaro y la arbolada ribera del Ebro. Fuente visual: maps.google.es/', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65777300, -0.87155500, '0101000020E6100000F949B54FC7E3EBBF8D98D9E731D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36380144776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36380144776.webp', 'https://www.flickr.com/photos/zaragozaantigua/36380144776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23251, 'Lavadero del Puente del Pilar c.1935', 'Imagen capturada en el gran lavadero al aire del Puente del Pilar y realizada, precisamente, con el fondo de la estructura del puente de Nuestra Se├▒ora del Pilar que le daba nombre. En primer t├®rmino, la pila de lavar ropa con una primera zona para el aclarado de la ropa, y una segunda para el lavado con jab├│n de tajo, que es donde posan las lavanderas usuarias. A la izquierda y tras la alameda, la extensa zona de los tendederos.', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST├ôRICO', 41.65766700, -0.87034300, '0101000020E61000004FAE2990D9D9EBBF4754A86E2ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15494930918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15494930918.webp', 'https://www.flickr.com/photos/zaragozaantigua/15494930918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23640, 'Calle de Jes├║s 1969', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 31/05/1969. En la imagen, el antiguo Cuartel de la Guardia Civil de la calle de Jes├║s, n┬║ 8, en el tramo hasta la calle Nicol├ís Funes.', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST├ôRICO', 41.65813200, -0.87216800, '0101000020E61000006EC493DDCCE8EBBFBD395CAB3DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15347091381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15347091381.webp', 'https://www.flickr.com/photos/zaragozaantigua/15347091381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23868, 'Zaragoza 1615', 'Escenario para el cap├¡tulo 35 de la serie de dibujos animados "Don Quijote de la Mancha". titulado "Camino de Barcelona". T├®mpera, ├üngel Santiago Chicharro, 1979. Buen aficionado a ver visiones, Alonso Quijano puede observar el futurista templo barroco del Pilar en el emplazamiento en que estaba la iglesia g├│tico-mud├®jar de Santa Mar├¡a del Pilar. En cualquier caso, en la segunda parte del "Quijote" can├│nico, el singular hidalgo de La Mancha pas├│ de largo de Zaragoza y se fue a Barcelona. Fuente: www.todocoleccion.net', 1615, 1615, 1615, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65716400, -0.87101400, '0101000020E6100000EA758BC058DFEBBFE50D30F31DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30663941224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30663941224.webp', 'https://www.flickr.com/photos/zaragozaantigua/30663941224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24062, 'Cuartel de San L├ízaro 1975', 'Imagen capturada en el interior del patio del cuartel de San L├ízaro, una lluviosa ma├▒ana de mediados del mes de noviembre, mientras el bombo de la suerte decide el destino castrense donde los j├│venes de la imagen habr├¡an de realizar el Servicio Militar Obligatorio. La gran mayor├¡a de ellos tendr├¡an que hacer turismo a otras regiones, incluyendo la provincia del S├íhara Occidental, entonces inmersa en un complicado proceso de descolonizaci├│n, a├║n sin terminar hoy. El pabell├│n por donde trepa una enredadera, recayente al arranque de la avenida de Catalu├▒a, donde estaba el ingreso principal al cuartel. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST├ôRICO', 41.65821400, -0.87368000, '0101000020E6100000BE6A65C22FF5EBBF7AE2395B40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32724240024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32724240024.webp', 'https://www.flickr.com/photos/zaragozaantigua/32724240024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24740, 'Convento de San L├ízaro 1890', 'Restos del convento de San L├ízaro de Zaragoza, luego cuartel, en 1890. Este edificio ser├í rehabilitado en 1916. Fuente visual: Zaragoza art├¡stica, monumental e hist├│rica. Anselmo Gasc├│n de Gotor, 1891.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15454917010.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15454917010.webp', 'https://www.flickr.com/photos/zaragozaantigua/15454917010/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24742, 'Circo Tom 1931', 'Observamos c├│mo la troupe de un circo con sus carromatos entra a Zaragoza por el puente del Pilar o de Hierro, con la torre de la Seo al fondo. Se dirigen al nuevo recinto ferial de Gran V├¡a, una vez inhabilitada la huerta de Santa Engracia para tales fines debido a las nuevas edificaciones. Fuente visual: "De las Fiestas del Pilar: la Feria", ilustraci├│n de Vigaray, 11-10-1931, archivo Heraldo de Arag├│n, en "Padre Ebro. El r├¡o Ebro y el siglo XX".', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST├ôRICO', 41.65679900, -0.87004600, '0101000020E6100000ED7F80B56AD7EBBFD38558FD11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15561199598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15561199598.webp', 'https://www.flickr.com/photos/zaragozaantigua/15561199598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24743, 'Camino de las Tablas 1930', 'Miguel Faci Abad. 1930. Imagen de un arrabalero grupillo de ni├▒os de etnia gitana, en el Barrio de Jes├║s. Al fondo, la margen derecha del Ebro y una vista parcial, tras la fachada del Palacio Arzobispal, del barrio de La Seo. Esta captura se ha realizado cerca del antiguo Puente de Tablas, del que quedaba una referencia en el lugar en que se encontraba esta chiquiller├¡a: cerca del Camino de las Tablas, actual Calle Puente Tablas. A derecha e izquierda de esta imagen, tendederos y lavaderos como el de Modesto Andr├®s. Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65723400, -0.87109500, '0101000020E61000001CB1169F02E0EBBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15574237569.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15574237569.webp', 'https://www.flickr.com/photos/zaragozaantigua/15574237569/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24747, 'Cuartel de San L├ízaro c.1888', 'Imagen del patio del cuartel de San L├ízaro, hacia 1888. Al fondo, el Pilar. Fuente: www.facebook.com/photo.php?fbid=10204391339677174&set...', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65791100, -0.87418400, '0101000020E610000083F755B950F9EBBFDE567A6D36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15747087251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15747087251.webp', 'https://www.flickr.com/photos/zaragozaantigua/15747087251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24769, 'Avenida Puente del Pilar 1990', 'Foto: Mariano Aladr├®n. Vista de la avenida Puente del Pilar desde el paso hom├│nimo sobre el Ebro, en 1990. Fuente: www.facebook.com/photo.php?fbid=10153056294537834&set...', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65677600, -0.87005500, '0101000020E6100000BA1457957DD7EBBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21649235600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21649235600.webp', 'https://www.flickr.com/photos/zaragozaantigua/21649235600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24771, 'Avenida Puente del Pilar 1990', 'Foto: Mariano Aladr├®n. Vista de la avenida Puente del Pilar con el puente hom├│nimo sobre el Ebro al fondo, en 1990. Fuente: www.facebook.com/photo.php?fbid=10153055973112834&set...', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65721700, -0.86972300, '0101000020E61000003C873254C5D4EBBF08B0C8AF1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22283360229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22283360229.webp', 'https://www.flickr.com/photos/zaragozaantigua/22283360229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24794, 'San L├ízaro 2009', 'Obras de construcci├│n del Centro de Interpretaci├│n de San L├ízaro, en octubre de 2009. Alberga restos del convento (1224), luego cuartel, derribado en 1983. Este peque├▒o museo permaneci├│ cerrado durante a├▒os, hasta que en 2016 se recuperaron las visitas, tras breves per├¡odos en 2010 y 2013. Fuente visual: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65801700, -0.87414400, '0101000020E6100000F6D37FD6FCF8EBBF249BABE639D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32470418653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32470418653.webp', 'https://www.flickr.com/photos/zaragozaantigua/32470418653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22715, 'Romareda 1976', 'Imagen capturada desde la altura de la torre de la Feria de Muestras con una interesante panor├ímica del entorno del inmediato pol├¡gono de la Romareda (antiguo de la Gran V├¡a). A la izquierda, el paseo de Isabel la Cat├│lica con la Residencia Sanitaria "Jos├® Antonio", el Colegio-Residencia de Nuestra Se├▒ora del Pilar para Hu├®rfanos e Hijos del Magisterio, y las destacadas torres de viviendas ubicadas al final del paseo. En el centro de la imagen, original estadio municipal de La Romareda durante el comienzo de las obras de ampliaci├│n y cubrimiento de las Tribunas de Gol Norte y Gol Sur, realizadas por la empresa constructora Obrasc├│n SA (integrante luego de la actual OHL) y que culminar├¡an en agosto del a├▒o siguiente tras casi duplicar durante el proceso el presupuesto inicial consignado, algo que en la larga etapa interdemocr├ítica no se publicitaba, luego no exist├¡a, asociado a conceptos como "sobrecostes", "mordidas", o "corrupci├│n" (que incluye tanto a corruptores como corruptos). A la derecha, iglesia parroquial de Santa M├│nica y vista parcial, al fondo, del Seminario. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63655900, -0.90191300, '0101000020E6100000BCCADAA678DCECBFBB7CEBC37AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29919916448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29919916448.webp', 'https://www.flickr.com/photos/zaragozaantigua/29919916448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24796, 'Calle de Jes├║s 2008', 'Imagen capturada en la calle de Jes├║s, durante el par├│n de la construcci├│n por la empresa (entre otras cosas) Sacyr Vallehermoso de las 197 viviendas de lujo de la inmediata parcela, aqu├¡ delimitada apenas por una red verde. Este proyecto, denominado "Balc├│n de San L├ízaro", arranc├│ en el a├▒o 2006 con el horizonte de que durante el prodigioso verano de 2008, en plena Expo, empezara a ser ocupado por residentes, y convertirse as├¡ en otra gran empresa realizada al hilo de la muestra internacional. Pero al poco de comenzar los trabajos de excavaci├│n de los cimientos y garajes, aparecieron sorprendentes restos arqueol├│gicos posiblemente vinculados al convento mercedario de San L├ízaro all├¡ fundado en el siglo XIII, as├¡ como un refugio a├®reo habilitado durante la guerra civil de 1936-39 en los bajos del cuartel hom├│nimo que all├¡ funcion├│ durante casi un siglo. Tras un par├│n t├®cnico prolongado, las obras retomaron su impulso definitivo en 2014 por la gestora Gesti├│n Com├║n, y la constructora Ferrovial. Centra la imagen el sesentero inmueble del n┬║ 1 de la calle de Juliana Larena, ├║nico testigo que perdura de la traza urbana de este tramo de la calle de Jes├║s. A su izquierda, el gran solar que perdura tras el derribo del cuartel de la Guardia Civil. A su derecha y al fondo, el antiguo molino de la Sal de San L├ízaro, y la ribera del r├¡o Ebro. En primer t├®rmino, y confrontando al otro lado de la calle, solar del desaparecido inmueble del n┬║ 2 de la calle de Jes├║s, en cuyos bajos estuvo el Cine Norte. Fuente visual: www.google.com/maps', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65817400, -0.87270300, '0101000020E6100000F4DF83D72EEDEBBFEC89AE0B3FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32790433218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32790433218.webp', 'https://www.flickr.com/photos/zaragozaantigua/32790433218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24816, 'Calle del Sobrarbe c.1893', 'Imagen capturada aprovechando el saliente sol, posiblemente desde la altura de la torre sure├▒a de la moderna iglesia parroquial de Nuestra Se├▒ora de Altab├ís, construida sobre una parte del antiguo Macelo, con una m├ís que interesante vista panor├ímica de la ciudad desde la margen izquierda. En primer t├®rmino, la calle del Sobrarbe y sus varias alturas o niveles. A la izquierda, e inmediatos, tejados del antiguo Macelo municipal y del convento de las carmelitas de San Jos├® del Arrabal. A la derecha, manzana delimitada entre la calle del Horno y la calle de Juslibol. Antes del Puente de Piedra destaca la zanja del empalme del ferrocarril a las l├¡neas de Barcelona y Pamplona, cubierta con el paso a la calle del Sobrarbe, por donde transitaban los tranv├¡as a propulsi├│n de sangre de la linea del Arrabal. Hacia la izquierda hac├¡an lo propio, por la carretera de Madrid a Barcelona, los de la l├¡nea del G├íllego. Hacia la derecha, el arranque de la ribere├▒a arboleda de Macanaz. Pasado el Ebro, panor├ímica edilicia con la monumental fachada del Palacio Arzobispal, tras el que emerge la torre y cimborrio de la Seo. Donde se abre la calle de la Lonja se destaca al fondo la torre de la iglesia de San Juan y San Pedro. A la derecha, la veterana Casa Consistorial y la Lonja como su anexo. Difumimada al fondo, la torre de la iglesia de San Gil Abad. A la derecha, tras la casa del marqu├®s de Ayerbe y la Casa de los Infantes, el templo del Pilar y su reci├®n terminada torre de Santiago.', 1893, 1893, 1893, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65886900, -0.87431400, '0101000020E610000010EB8D5A61FAEBBF93ACC3D155D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49008106072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49008106072.webp', 'https://www.flickr.com/photos/zaragozaantigua/49008106072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24825, 'Av. del Puente del Pilar c.1992', 'La avenida del Puente del Pilar durante las obras de renovaci├│n de conducciones y pavimentos, en una imagen capturada junto a las antiguas naves de Pikol├¡n, a la derecha, con una vista que alcanza desde el inmediato cruce con la calle del Pilar y el camino del Vado, hasta el fondo donde en la avenida de Catalu├▒a se perfilan la Casa A├¡sa Farasdu├®s o Casa Sol├íns y la antigua f├íbrica de galletas Patria, e incluso los recientes bloques de la calle del Marqu├®s de la Cadena y la plaza de W. Amadeus Mozart.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST├ôRICO', 41.65749900, -0.86950700, '0101000020E61000000C94145800D3EBBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450894223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450894223.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450894223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25405, 'Desde San L├ízaro c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C├¡a. 1860-1886. "Puente sobre el Ebro desde las ruinas de San L├ízaro". Puente de Piedra, con el Pilar al fondo.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65806800, -0.87430300, '0101000020E6100000166EF9484AFAEBBFA6457D923BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14843705646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14843705646.webp', 'https://www.flickr.com/photos/zaragozaantigua/14843705646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25407, 'Ribera del Ebro 1957', 'Un grupo de reclutas durante el servicio militar obligatorio o mili en el cuartel de San L├ízaro, establecido a finales del siglo XIX sobre el antiguo convento del mismo nombre, posan en la ribera del Ebro con el fondo del puente de Piedra y el Pilar, del que destacan sus dos ├║ltimas torres en construcci├│n. Fuente: Colecci├│n Joaqu├¡n Cabezas.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65776300, -0.87389500, '0101000020E6100000D769A4A5F2F6EBBF6AC2F69331D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914204126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914204126.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914204126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25445, 'Puente de Tablas 2007', 'Estribo norte del puente de Tablas, excavado durante las obras de remodelaci├│n del paseo de la Ribera, entre el puente del Pilar y el de Piedra. El antiguo puente de Tablas sobre el r├¡o Ebro para paso de la carretera real de Madrid a Barcelona fue reconstruido tras varias riadas, como la de febrero de 1643 o la del 23 de junio de 1775. Una nueva avenida, el 10 de junio de 1801, acab├│ para siempre con ├®l. En 1803 se proyect├│ levantarlo de nuevo, pero hasta 1895 no se inaugur├│ el puente del Pilar, en sus inmediaciones. En 2008, en esta ubicaci├│n se inaugur├│ un mirador dise├▒ado por Claus Bury, dentro del programa de Intervenciones Art├¡sticas de la Expo. Fuente visual: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65679000, -0.87131200, '0101000020E6100000639813B4C9E1EBBF802BD9B111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32306673092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32306673092.webp', 'https://www.flickr.com/photos/zaragozaantigua/32306673092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25862, 'Calle de Jes├║s 2007', 'Instant├ínea de las traseras del edificio de la calle de Jes├║s 2, en el momento de ser derribado en febrero de 2007. Albergaba en sus bajos el cine Norte, abierto entre 1953 y 1981. Fuente visual: demoliciones.usabiaga.com/', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65821100, -0.87287700, '0101000020E610000069C70DBF9BEEEBBF096F0F4240D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21923079511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21923079511.webp', 'https://www.flickr.com/photos/zaragozaantigua/21923079511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25866, 'Calle de Jes├║s 2007', 'Foto: Mar├¡a Torres-Solanot. Derribo del edificio del n├║mero 2 de la calle de Jes├║s, en febrero de 2007. Albergaba en sus bajos el cine Norte, abierto entre 1953 y 1981, con su puerta principal, en la imagen, tras el sem├íforo. Fuente: Heraldo de Arag├│n.', 2007, 2007, 2007, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65828100, -0.87286800, '0101000020E61000009C3237DF88EEEBBF024A438D42D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31861913510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31861913510.webp', 'https://www.flickr.com/photos/zaragozaantigua/31861913510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25989, 'Zaragoza 1749', 'Dibujo de Luis Macaya para la edici├│n argentina de 1943 del ÔÇ£Diario y derrotero de los viajes que ha hecho el Padre Fray Pedro Jos├® de Parras, desde que sali├│ de la ciudad de Zaragoza, en Arag├│n, para la Am├®rica; con una brev├¡sima relaci├│n de lo que personalmente ha experimentado en diversos pa├¡ses y de las cosas m├ís notables que en ellos ha vistoÔÇØ (1749-1753), escrito por el turolense Pedro Jos├® de Parras, que viaj├│ de Cari├▒ena a Paraguay. La ilustraci├│n refleja el estado de la ciudad a principios del siglo XX, aunque se refiere a 1749. El fraile dice de su paso por Zaragoza: "No omitir├® ser esta ciudad la m├ís hermosa y aseada que he visto en lo que he transitado. Tiene despejad├¡simas calles, y la que llaman del Coso, no tiene en Espa├▒a semejante. S├│lo la calle de Alcal├í, en Madrid, le parece un poco, pero no es tan buena. Tiene as├¡ mismo cerca de cincuenta comunidades. Sujetas al provincial de San Francisco, hay seis. Son suntuosos sus palacios. En una o en otra ciudad, se hallar├í alg├║n templo que iguale a los de Zaragoza, pero a todos juntos no pueden compararse los de alguna otra ciudad, fuera de Roma. La Universidad es famosa y bien formalizada, y los estudios en ninguna parte se hallar├ín m├ís florecientes que en este reino. La ciudad tiene fertil├¡sima ribera y varios florid├¡simos monasterios en lo m├ís ameno de sus huertas, y entre todos sobresalen las dos cartujas de la Concepci├│n y Aula Dei. B├í├▒anle dos r├¡os muy caudalosos; el uno es G├íllego y el otro Ebro, que es navegable hasta Tortosa, y que no hay otro en Espa├▒a que pueda igualarle, s├¡ s├│lo Guadalquivir. S├│lo tiene un defecto, y es no sea puerto de mar; por cuya causa est├í la ciudad sin aquel concurso de gente que es capaz, aunque siempre est├í bien surtida de tropa. Abunda mucho de aceite, vino, lanas, frutas, hortalizas, lino, seda, y finalmente, hay con abundancia de cuantos efectos produce la Espa├▒a. Tiene la ciudad Audiencia, Tribunal de Inquisici├│n, capit├ín general del Reino, intendente de la Real Hac', 1749, 1749, 1749, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65753600, -0.87367200, '0101000020E610000008CA6DFB1EF5EBBFA9F8BF232AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18834347511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18834347511.webp', 'https://www.flickr.com/photos/zaragozaantigua/18834347511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26017, 'Playas del Ebro 1968', 'Veraniega imagen de una de las famosas playas del Ebro como interesante destino del turismo interior en la Espa├▒a del "milagro" econ├│mico, en la prodigiosa d├®cada. La captura se ha realizado en las traseras del Colegio de San Miguel, antiguo molino de sal y harina, y una de las playas urbanas durante el est├¡o. La calidad del agua no era muy alta, el estado de la ribera dejaba bastante que desear, y las escombreras de primer t├®rmino desluc├¡an un poco la cosa, pero los est├índares de calidad de la concurrencia no eran demasiado puntillosos. Eso s├¡, la vista de la magn├¡fica margen derecha, con el puente de Piedra, el Pilar, el Ayuntamiento, la Lonja, el palacio Arzobispal... et cetera, luc├¡a inmejorable. En Zaragoza, con un neum├ítico, y un paraguas, ya tienes ba├▒os de sol y agua, al menos en aquellos a├▒os. Fuente visual: Walter Schr├Âder (www.bildindex.de/)', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65669900, -0.87154500, '0101000020E610000016C1FF56B2E3EBBF70287CB60ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23227617450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23227617450.webp', 'https://www.flickr.com/photos/zaragozaantigua/23227617450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26049, 'Ribera del Ebro 2006', 'Foto: Mar├¡a Torres-Solanot. Diciembre de 2006. Vista de la explanaci├│n de los terrenos, tras el derribo de las naves que all├¡ hab├¡a, del tramo de ribera del Ebro entre los puentes de Hierro y de Piedra (al fondo). Esta zona trasera del barrio de Jes├║s es conocida como Balc├│n de San L├ízaro. El edificio que permanece en pie es el antiguo molino de la sal, luego colegio de San Miguel, abandonado a finales de los setenta. Hoy es un restaurante. El otro edificio que dejar├í en pie esta actuaci├│n es el del antiguo cine Norte, en la calle de Jes├║s 2; ser├í derribado en febrero de 2007. El entorno, urbanizado mediante un vial y la construcci├│n de edificios (a la derecha), recibir├í despu├®s el nombre de paseo de la Ribera, como los tramos que lo acompa├▒an a este y oeste. Al fondo, paseo de Echegaray y Caballero, con las torres de la Seo y el Pilar. Fuente: Heraldo de Arag├│n.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65707900, -0.87149400, '0101000020E61000008E20956247E3EBBFB7F1272A1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32002422512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32002422512.webp', 'https://www.flickr.com/photos/zaragozaantigua/32002422512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21260, 'Plaza de las Eras 1907', 'Postal. "Colecci├│n Patria y Fe n├║m. 38, Zaragoza 1908 - Centenario de los Sitios", 1907. "Escenario de muy re├▒idas campa├▒as por su proximidad a los conventos de San Agust├¡n y Santa M├│nica que fueron constante blanco de las bater├¡as francesas y brecha por donde intentaron penetrar uno y otro d├¡a." En la imagen, la plaza desde la fuente de agua que hab├¡a en su centro. Hacia la izquierda, contin├║a la calle Manuela Sancho para desembocar m├ís adelante en la calle Doctor Palomar. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65015400, -0.87174000, '0101000020E610000068AED3484BE5EBBF8AAE0B3F38D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20584647970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20584647970.webp', 'https://www.flickr.com/photos/zaragozaantigua/20584647970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21953, 'Convento Capuchinas c.1943', 'Fachada del Convento de las Madres Clarisas Capuchinas, calle Manuela Sancho 40. Esta congregaci├│n vino a Zaragoza desde Barcelona a comienzos del siglo XVII, y se instalaron justo enfrente del convento de las MM. Carmelitas Descalzas, en la plaza de Santa Engracia. En el siglo XIX, la reordenaci├│n urbana del nuevo Sal├│n de Santa Engracia les dej├│ sin sitio, y anduvieron unos a├▒os en la provisionalidad. En 1877 se instalaron en la calle Manuela Sancho, en un convento de nueva planta dise├▒ado por Pascual Bravo hasta que, menos de un siglo despu├®s, otro ejemplo de la no oficial "Operaci├│n Conventos y Colegios Privados", vendieron y se trasladaron a la periferia, calle Monasterio de Nuestra Se├▒ora de los ├üngeles (m├ís all├í de la V├¡a Hispanidad). El convento de la imagen fue derribado en 1973, y sobre ├®l se levant├│ la urbanizaci├│n hoy existente, entre la calle Manuela Sancho, y la calle Asalto. Fuente visual: Dibujo de Ambrosio Ruste en la revista La Cadiera.', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST├ôRICO', 41.64988200, -0.87165400, '0101000020E6100000C5AEEDED96E4EBBF292158552FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19302059572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19302059572.webp', 'https://www.flickr.com/photos/zaragozaantigua/19302059572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23589, 'Torre de Bruil c.1959', 'Imagen de la fachada recayente a la calle del Asalto, confrontando con el convento de religiosas de Santa M├│nica, de la denominada Torre de Bruil (1842-1868), que aunque desde 1878 era propiedad de la familia Monserrat, conserv├│ su original nombre de forma no oficial. Los de la imagen eran los edificios tras los que se abr├¡a el ordenado juego de paseos, p├®rgolas, arbolado y vegetaci├│n decorativa que caracterizaba este decimon├│nico y singular espacio de recreo, trufado de enclaves bizarros como su monta├▒a artificial. A comienzos de los a├▒os 50 del siglo XX el Ayuntamiento inici├│ el proceso para expropiar este terreno y convertirlo en un parque p├║blico. En 1959 los tribunales ratificaron esta pretensi├│n, y a cambio casi cinco millones y medio de pesetas pagadas al propietario, su titularidad pas├│ a beneficio de la ciudad. Poco despu├®s, tras una intensa remodelaci├│n que incluy├│ el derribo de estos inmuebles, ser├¡a inaugurado como Parque Bruil.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST├ôRICO', 41.65022800, -0.87001200, '0101000020E6100000E814E46723D7EBBFC478CDAB3AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50068064947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50068064947.webp', 'https://www.flickr.com/photos/zaragozaantigua/50068064947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23592, 'Plaza de las Eras 1990', 'Imagen capturada desde la altura del inmueble del n┬║ 40 de la calle de Manuela Sancho, con vista de la plaza de las Eras previa a la reforma que, tras la renovaci├│n de servicios, evitar├¡a que este espacio siguiera siendo b├ísicamente un aparcamiento en superficie. Entre los nuevos elementos decorativos de la nueva plaza, destacar├¡an unas singulares p├®rgolas, y una escultura en bronce de la mitol├│gica diosa Hera, con homofon├¡a id├®ntica que el nombre de la plaza, aunque su simbolismo no tuviera nada que ver con ella. Tal vez por ello, y por estar dispuesta en altura en un espacio peque├▒o, resulta ser una de las esculturas m├ís inapreciables de la ciudad.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65015600, -0.87177100, '0101000020E6100000293DD34B8CE5EBBF2BA6D24F38D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50370134818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50370134818.webp', 'https://www.flickr.com/photos/zaragozaantigua/50370134818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23714, 'Escuelas del Terminillo 1923', 'Aspecto de la entrada al edificio de las Escuelas del Terminillo o Escuela Asilo de las Hermanas de San Vicente de Pa├║l, fundada por el arzobispo Juan Soldevila en 1914. La foto se ha tomado en el lugar donde ├®ste muri├│ a causa de los disparos de un comando anarquista. Un mausoleo fue levantado all├¡, que permaneci├│ en las traseras del Colegio Santa Mar├¡a Reina, calle La Milagrosa, hasta 2024. Entonces esa cruz-monolito fue trasladada al patio del Cedro del palacio Arzobispal, en la esquina de la calle del Sepulcro con la plaza de San Bruno. Fuente: eszaragoza.blogspot.com', 1923, 1923, 1923, 'Anos 20', 'UNIVERSIDAD', 41.64452000, -0.90479400, '0101000020E6100000A9BEF38B12F4ECBF18CFA0A17FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26134114535.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26134114535.webp', 'https://www.flickr.com/photos/zaragozaantigua/26134114535/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23599, 'Cisterna romana siglo I', 'La mayor cisterna romana hallada en Zaragoza, excavada entre 1990 y 1991, se ubicaba en el actual entorno de la plaza de las Eras, concretamente en el solar que ocupa el actual edificio de la calle de Manuela Sancho 50, construido en 2001. Ese solar, en forma de ÔÇ£LÔÇØ, estuvo ocupado antes de su excavaci├│n por edificaciones situadas entre la actual calle del Asalto 69 y la de Cant├¡n y Gamboa 34, junto al convento de las Madres Clarisas Capuchinas (1877-1973) de la calle de Manuela Sancho 40. El periodista Mariano Garc├¡a public├│ en Heraldo de Arag├│n el 10 de enero de 2026 un art├¡culo en el que divulgaba el estudio de Francisco de As├¡s Escudero Escudero y Mar├¡a Pilar Galve Izquierdo sobre "La cisterna romana de la plaza Eras de Zaragoza y otras cisternas y dep├│sitos de Caesaraugusta", incluido en el libro "Aquae Urbium. El ciclo urbano del agua en la Hispania romana" (Editorial Universidad de Sevilla, 2025). En ese estudio los autores destacan que la cisterna, construida a finales del siglo I o comienzos del II, es la m├ís importante hallada en Zaragoza, debido a sus grandes dimensiones. Pese a que su planta rectangular no se hall├│ completa, de los restos se infiri├│ que tuvo una superficie cercana a los 90 metros cuadrados. Estaba construida con opus caementicium (hormig├│n romano), y sus muros ten├¡an un grosor de al menos dos metros. Eso hace suponer que el edificio era de altura considerable, que lo har├¡a visible desde gran parte de la ciudad. Un tubo de plomo conservado, por el que desaguaba la cisterna, se hallaba a cierta altura, lo que confirmaba la funci├│n de decantaci├│n de la estructura, dejando en el fondo del dep├│sito las impurezas. El agua almacenada provendr├¡a de un castellum aquae (cisterna principal), situado posiblemente al sur de la ciudad, en el actual eje del paseo de la Independencia. Contrariamente a la tesis defendida hasta ahora, ello confirmar├¡a que el agua de boca de la ciudad proven├¡a del r├¡o Huerva, y no del G├íllego. Tambi├®n se han encontrado otr', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.64993300, -0.87132300, '0101000020E61000005D15A8C5E0E1EBBFABCB290131D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55037984470.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55037984470.webp', 'https://www.flickr.com/photos/zaragozaantigua/55037984470/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
